/// Integration tests for the Beatrice audio pipeline
/// Uses deterministic synthetic WAV files (generated by scripts/generate-test-audio.mjs)
/// to verify onset detection, feature extraction, classification, tempo estimation,
/// quantization, and arrangement.

use std::fs;
use std::path::PathBuf;

use beatrice_lib::audio::{self, OnsetConfig};
use beatrice_lib::events::{self, EventClass, HeuristicClassifier};
use beatrice_lib::groove::{self, Grid, GridDivision, GrooveFeel, QuantizeSettings, TimeSignature};

fn test_audio_dir() -> PathBuf {
    PathBuf::from(env!("CARGO_MANIFEST_DIR"))
        .parent()
        .unwrap()
        .join("test-audio")
}

fn load_test_wav(filename: &str) -> audio::AudioData {
    let path = test_audio_dir().join(filename);
    let bytes = fs::read(&path).unwrap_or_else(|e| {
        panic!(
            "Failed to read test file {}: {}. Run 'node scripts/generate-test-audio.mjs' first.",
            path.display(),
            e
        )
    });
    audio::ingest_wav(&bytes).unwrap_or_else(|e| {
        panic!("Failed to parse {}: {}", filename, e)
    })
}

// =============================================================================
// Feature extraction + classification on individual archetype files
// =============================================================================

#[test]
fn test_kick_classifies_as_bilabial_plosive() {
    let audio = load_test_wav("test-kick.wav");
    let mono = audio.to_mono();
    let features = audio::extract_features(&mono, audio.sample_rate);

    println!("KICK features: centroid={:.1} zcr={:.4} low={:.3} mid={:.3} high={:.3} peak={:.3} crest={:.2}",
        features.spectral_centroid, features.zcr,
        features.low_band_energy, features.mid_band_energy, features.high_band_energy,
        features.peak_amplitude, features.crest_factor);

    let classifier = HeuristicClassifier::new();
    let result = classifier.classify(&features);

    println!("KICK classification: {:?} confidence={:.3}", result.class, result.confidence);
    println!("  all_scores: {:?}", result.all_scores);

    assert_eq!(result.class, EventClass::BilabialPlosive,
        "Expected BilabialPlosive, got {:?}. Features: centroid={:.1} low_band={:.3} zcr={:.4}",
        result.class, features.spectral_centroid, features.low_band_energy, features.zcr);
    assert!(result.confidence > 0.6, "Confidence {:.3} too low", result.confidence);
}

